const n=JSON.parse(`{"key":"v-688d602a","path":"/vanblog/Linux%E8%AE%BE%E7%BD%AE%E5%AE%9A%E6%97%B6%E4%BB%BB%E5%8A%A1.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 crontab命令是Unix和Linux用于设置周期性被执行的指令。该命令从标准输入设备读取指令，并将其存放于“crontab”文件中，以供之后读取和执行。crontab命令常见于 Unix 和 类Unix 的操作系统之中。通常，crontab储存的指令被守护进程激活， crond常常在后台运行，每一分钟检查是否有预定的作业需要执行。 该命令依赖于cron，可通过下面命令安装和启用： # 安装 sudo apt-get install cron # 启动 systemctl start cron # 查看状态 systemctl status cron","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/Linux%E8%AE%BE%E7%BD%AE%E5%AE%9A%E6%97%B6%E4%BB%BB%E5%8A%A1.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 crontab命令是Unix和Linux用于设置周期性被执行的指令。该命令从标准输入设备读取指令，并将其存放于“crontab”文件中，以供之后读取和执行。crontab命令常见于 Unix 和 类Unix 的操作系统之中。通常，crontab储存的指令被守护进程激活， crond常常在后台运行，每一分钟检查是否有预定的作业需要执行。 该命令依赖于cron，可通过下面命令安装和启用： # 安装 sudo apt-get install cron # 启动 systemctl start cron # 查看状态 systemctl status cron"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":1.42,"words":427},"filePathRelative":"vanblog/Linux设置定时任务.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>crontab命令是Unix和Linux用于设置周期性被执行的指令。该命令从标准输入设备读取指令，并将其存放于“crontab”文件中，以供之后读取和执行。crontab命令常见于 Unix 和 类Unix 的操作系统之中。通常，crontab储存的指令被守护进程激活， crond常常在后台运行，每一分钟检查是否有预定的作业需要执行。</p>\\n<p>该命令依赖于<code>cron</code>，可通过下面命令安装和启用：</p>\\n<div class=\\"language-bash line-numbers-mode\\" data-ext=\\"sh\\"><pre class=\\"language-bash\\"><code><span class=\\"token comment\\"># 安装</span>\\n<span class=\\"token function\\">sudo</span> <span class=\\"token function\\">apt-get</span> <span class=\\"token function\\">install</span> <span class=\\"token function\\">cron</span>\\n\\n<span class=\\"token comment\\"># 启动</span>\\nsystemctl start <span class=\\"token function\\">cron</span>\\n\\n<span class=\\"token comment\\"># 查看状态</span>\\nsystemctl status <span class=\\"token function\\">cron</span>\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>","autoDesc":true}`);export{n as data};
